import{_ as t,o as r,c as a,a7 as p}from"./chunks/framework.BgApuQ2e.js";const n="/images/universe/1-surprise.png",s="/images/universe/2-fun-room.png",o="/images/universe/SIZE-DRAWING-1v3.jpg",i="/images/universe/SIZE-DRAWING-2v2.jpg",h="/images/universe/SIZE-DRAWING-3v4.jpg",l="/images/universe/3.1-screenshot.jpeg",g="/images/universe/3.3-screenshot.jpeg",m="/images/universe/3.2-screenshot.jpeg",u="/images/universe/4-Zoom.png",c="/images/universe/5-review.jpg",w="/images/universe/pinit_fg_en_rect_gray_20.png",S=JSON.parse('{"title":"The Big and the Small","description":"","frontmatter":{"title":"The Big and the Small","titleZh":"大与小","date":"2020-09-22T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2020/09/universe.html","slug":"universe"},"headers":[],"relativePath":"posts/universe.md","filePath":"posts/universe.md","lastUpdated":1782886257000}'),_={name:"posts/universe.md"};function b(f,e,d,k,y,v){return r(),a("div",null,[...e[0]||(e[0]=[p('<h1 id="大与小-·-the-big-and-the-small" tabindex="-1">大与小 · The Big and the Small <a class="header-anchor" href="#大与小-·-the-big-and-the-small" aria-label="Permalink to &quot;大与小 · The Big and the Small&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2020/09/universe.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2020/09/universe.html</a> · 2020-09-22</p></blockquote><p>我有个惊喜要给你。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/1-surprise.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>我马上就告诉你是什么。先来玩会儿吧。跟我来。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/2-fun-room.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p><img src="'+o+'" alt=""> <img src="'+i+'" alt=""> <img src="'+h+'" alt=""></p><p>我以前从没告诉过任何人,但其实我就住在这个乐趣屋里。我刚刚带你参观的其实是我家——我人生的一大部分时间都在这儿琢磨各种东西的大小。</p><p>我时不时会有客人来乐趣屋,但几分钟后,他们通常就玩够了,把我一个人留下,继续跟我那些危机作斗争。但有一天,发生了一件出乎意料的事。</p><p>那是 2013 年。Wait But Why 才刚开了几个月。我收到了一个叫 Philipp Dettmer 的人的邮件。他名字里那俩 pp 和 tt 让我有点不安,但我还是决定读一下他写了啥。</p><p>他解释说他住在德国,做各种主题的动画科普视频,有点像 Wait But Why,只不过是不同的媒介。我去他的 YouTube 主页看了看。频道名是一串随机字母:</p><p>kurzgesagt</p><p>后来知道这在德语里是「简而言之 (In a Nutshell)」的意思,但我当时并不知道,而且<em>差一点</em>就要跟这位 Philipp Dettmer 彻底拜拜了——就在这时,我决定看一个他的视频。</p><p><em>太带劲了</em>。</p><p>我又看了一个。又一个。然后我突然反应过来。</p><p>Philipp——这个德国来的陌生男人——<em>也住在乐趣屋里</em>。</p><p>第二天,我们通了电话。有太多要聊的了。我们决定必须一起搞点事情,最后定下来把<a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">我早期的一篇文章</a>改编成一个 <a href="https://www.youtube.com/watch?v=2XkV6IpV2Y0&amp;ab_channel=Kurzgesagt%E2%80%93InaNutshell" target="_blank" rel="noreferrer">kurzgesagt 视频</a>。<a href="#footnote-1-8973">1</a></p><p>那之后的七年里,Philipp 和我成了很好的朋友,他家每一个 kurzgesagt 视频我都没错过。每次我俩一起吃饭,都直奔乐趣屋去聊宇宙。几个月前,我们决定再合作一次。是时候让乐趣屋公开亮相了。</p><p>在过去的某个时间点,我们俩都迷上了两位乐趣屋的偶像人物,Cary 和 Michael Huang,网上人称黄氏双胞胎 (Huang Twins)。双胞胎做了<a href="https://www.htwins.net/" target="_blank" rel="noreferrer">很多酷东西</a>,但我们最爱的还是他们的<a href="https://www.htwins.net/scale2/" target="_blank" rel="noreferrer">宇宙尺度 (Scale of the Universe)</a> 小玩具。</p><p>受他们启发,我们决定大干一场。我们想做出自己能想象到的最棒的尺寸探索器。我们把它叫做 Universe in a Nutshell(果壳中的宇宙)。</p><p>当然,实际花的时间大概是我们预想的 18 倍。我们花了相当长时间头脑风暴界面设计,然后 Philipp 和了不起的 kurzgesagt 团队一头扎进了插画和动画的制作,而我则和团队一起搞文字讲解。</p><p>几千个人力工时之后,app 终于做完了。250 个天体和物体、30,000 多字的讲解和趣味小知识、恰到好处的氛围音乐,以及我们自认为相当棒的界面。</p><p>它是这么用的:</p><p>这个 app 是一堵巨大的墙。这堵墙大得离谱——大到能把整个星系原尺寸放上去。这堵墙的分辨率也高得离谱——高到能容纳亚原子粒子的清晰图像。</p><p>我知道我把它当成一个真实存在的东西来讲有点怪,但我有充分的理由:要想获得完整的震撼效果,你必须意识到自己在看什么。你并不是在一条由各种物体组成的隧道里前后移动——之所以感觉像那样,是因为你的大脑拒绝接受你所看到的那些尺寸有多疯狂。通过一遍又一遍地提醒自己:所有这些物体都是「画」在同一堵二维墙上的,你才有希望体验到一些有趣的脑洞时刻。</p><p>app 长这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/3.1-screenshot.jpeg" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>还有这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/3.3-screenshot.jpeg" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>还有这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/3.2-screenshot.jpeg" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>而且有三种缩放方式:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/4-Zoom.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>你可以点任何一个物体来看讲解和趣味小知识。你刚才在趣味展厅里读到的所有事实也都在 app 里,还有一百万件别的东西。(趣味展厅里那些「就 Wait But Why 而言好得出奇」的插画都是 Kurzgesagt 的作品。别以为这就是新常态了。)</p><p>还有三件事:</p><p>1)app 在美区售价 3 美元,考虑到一堵魔法无限墙怎么也得卖 250 万美元,这简直是白菜价。</p><p>2)如果你喜欢这个 app,请给它打分或写评论。比如,这是我写的评论:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2020/09/5-review.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>3)这是 app 的 V1 版本。做这个 app 的过程中,我们一直在边上讨论 V2、V3 以及之后版本的各种可能性。我们今天上线,但这只是开始。我们想让这个 app 成为一个不断变得越来越好的大脑游乐场。而这就轮到你出场了。</p><p>在使用 app 的过程中,只要你冒出「真希望 app 能做 X」或者「如果 app 能做到 Y 就太酷了」这种念头,我们都想听。既然这是 V1 版本,那当然,只要你觉得「这里不太对劲」或者「我觉得这个事实有问题」,也请告诉我们。在 app 的菜单里,你会看到一个「feedback」标签,点进去可以看到反馈邮箱 <a href="/cdn-cgi/l/email-protection.html#fb9a8b8b9d9e9e9f999a9890bb908e89819c9e889a9c8fd594899c">email address</a>,把你的想法告诉我们。</p><h2 id="好了-给你。iphone-ipad-点左边的-app-android-点右边的。" tabindex="-1">好了,给你。<strong>iPhone/iPad 点左边的 app,Android 点右边的。</strong> <a class="header-anchor" href="#好了-给你。iphone-ipad-点左边的-app-android-点右边的。" aria-label="Permalink to &quot;好了,给你。**iPhone/iPad 点左边的 app,Android 点右边的。**&quot;">​</a></h2><h2 id="另外-为了庆祝-app-上线-kurzgesagt-今天也做了他们自己的一次趣味小屋之旅——一个关于恒星大小的有趣视频。" tabindex="-1">**另外:**为了庆祝 app 上线,Kurzgesagt 今天也做了他们自己的一次趣味小屋之旅——<a href="https://youtu.be/3mnSDifDSxQ" target="_blank" rel="noreferrer"><strong>一个关于恒星大小的有趣视频</strong></a>。 <a class="header-anchor" href="#另外-为了庆祝-app-上线-kurzgesagt-今天也做了他们自己的一次趣味小屋之旅——一个关于恒星大小的有趣视频。" aria-label="Permalink to &quot;**另外:**为了庆祝 app 上线,Kurzgesagt 今天也做了他们自己的一次趣味小屋之旅——[**一个关于恒星大小的有趣视频**](https://youtu.be/3mnSDifDSxQ)。&quot;">​</a></h2><p><strong>结尾部分:</strong></p><p>如果你喜欢 Wait But Why,来注册我们保证不烦人的 <strong><a href="https://mailchi.mp/waitbutwhy/email-signup" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章一发布我们就发给你。</p><h2 id="想支持-wait-but-why-访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,<a href="https://www.patreon.com/waitbutwhy" target="_blank" rel="noreferrer"><strong>访问我们的 Patreon 页面</strong></a>。 <a class="header-anchor" href="#想支持-wait-but-why-访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,[**访问我们的 Patreon 页面**](https://www.patreon.com/waitbutwhy)。&quot;">​</a></h2><p><strong>更多趣味小屋之旅:</strong></p><p><a href="https://waitbutwhy.com/2014/05/fermi-paradox.html" target="_blank" rel="noreferrer"><strong>费米悖论 (The Fermi Paradox)</strong></a></p><p><a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer"><strong>SpaceX 那篇</strong></a></p><p><a href="https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html" target="_blank" rel="noreferrer"><strong>千万亿颗 Sour Patch Kids 软糖那篇</strong></a></p><p><a href="https://waitbutwhy.com/2014/11/1000000-grahams-number.html" target="_blank" rel="noreferrer"><strong>以及一次不那么有趣的小屋之旅</strong></a></p><hr><ol><li>Kurzgesagt 在 2018 年做了一个<a href="https://www.youtube.com/watch?v=5TbUxGZtwGI&amp;ab_channel=Kurzgesagt%E2%80%93InaNutshell" target="_blank" rel="noreferrer">更新版视频</a>。<a href="#note-1-8973">↩</a></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2020/09/universe.html&amp;description=The%20Big%20and%20the%20Small" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p>',54)])])}const T=t(_,[["render",b]]);export{S as __pageData,T as default};
